  Alert,
  Snackbar,
  CircularProgress,
  LinearProgress,
  useTheme
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  DarkMode as DarkModeIcon,
  LightMode as LightModeIcon,
  OpenInNew as OpenInNewIcon,
  Sync as SyncIcon
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import { getSubscriptions, updateSubscription, deleteSubscription, createSubscription } from '../services/api';

const Subscriptions = ({ mode, setMode, onDashboardClick }) => {
  const theme = useTheme();
  const [subscriptions, setSubscriptions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);
  const [selectedSubscription, setSelectedSubscription] = useState(null);
  const [editSubscription, setEditSubscription] = useState({
    name: '',
    url: '',
    interval: 3600
  });

  useEffect(() => {
    fetchSubscriptions();
  }, []);

  const fetchSubscriptions = async () => {
    try {
      setLoading(true);
      const data = await getSubscriptions();
      setSubscriptions(data);
    } catch (err) {
      setError('Failed to load subscriptions');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenDialog = (subscription = null) => {
    if (subscription) {
      setSelectedSubscription(subscription);
      setEditSubscription(subscription);
    } else {
      setSelectedSubscription(null);
      setEditSubscription({
        name: '',
        url: '',
        interval: 3600
      });
    }
    setOpenDialog(true);
  };

  const handleCloseDialog = () => {
    setOpenDialog(false);
    setSelectedSubscription(null);
    setEditSubscription({
      name: '',
      url: '',
      interval: 3600
    });
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      if (selectedSubscription) {
        await updateSubscription(selectedSubscription.id, editSubscription);
      } else {
        await createSubscription(editSubscription);
      }
      await fetchSubscriptions();
      setSuccess(true);
      handleCloseDialog();
    } catch (err) {
      setError('Failed to save subscription');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    try {
      setLoading(true);
      await deleteSubscription(id);
      await fetchSubscriptions();
      setSuccess(true);
    } catch (err) {
      setError('Failed to delete subscription');
    } finally {
      setLoading(false);
    }
  };

  const formatBytes = (bytes) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const cardStyle = {
    height: '100%',
    transition: 'all 0.2s ease-in-out',
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(145deg, rgba(26,35,126,0.7), rgba(49,27,146,0.7))'
      : 'linear-gradient(145deg, rgba(255,255,255,0.9), rgba(255,255,255,0.95))',
    backdropFilter: 'blur(10px)',
    border: theme.palette.mode === 'dark'
      ? '1px solid rgba(255,255,255,0.1)'
      : '1px solid rgba(255,255,255,0.5)',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 4px 12px 0 rgba(0,0,0,0.3), 0 2px 4px -1px rgba(0,0,0,0.4)'
      : '0 4px 12px 0 rgba(31,38,135,0.15), 0 2px 4px -1px rgba(31,38,135,0.2)',
    '&:hover': {
      transform: 'translateY(-2px)',
      boxShadow: theme.palette.mode === 'dark'
        ? '0 6px 16px 0 rgba(0,0,0,0.4), 0 3px 6px -2px rgba(0,0,0,0.5)'
        : '0 6px 16px 0 rgba(31,38,135,0.25), 0 3px 6px -2px rgba(31,38,135,0.3)',
    }
  };

  const headerCardStyle = {
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(90deg, #1a237e 0%, #311b92 100%)'
      : 'linear-gradient(90deg, #3949ab 0%, #5e35b1 100%)',
    color: '#fff',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 4px 12px 0 rgba(0,0,0,0.3), 0 2px 4px -1px rgba(0,0,0,0.4)'
      : '0 4px 12px 0 rgba(31,38,135,0.15), 0 2px 4px -1px rgba(31,38,135,0.2)',
    mb: 1.5,
    backdropFilter: 'blur(10px)',
    border: '1px solid rgba(255,255,255,0.1)',
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: {
        duration: 0.3,
      }
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">操作成功</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Card sx={headerCardStyle}>
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" justifyContent="space-between">
            <Stack direction="row" alignItems="center" spacing={2}>
              <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
                订阅管理
              </Typography>
              {loading && (
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
                </Box>
              )}
            </Stack>
            <Stack direction="row" spacing={1}>
              <IconButton
                size="small"
                onClick={onDashboardClick}
                sx={{ 
                  color: 'rgba(255,255,255,0.8)',
                  '&:hover': { 
                    color: '#fff',
                    backgroundColor: 'rgba(255,255,255,0.1)' 
                  }
                }}
              >
                <OpenInNewIcon fontSize="small" />
              </IconButton>
              <IconButton
                size="small"
                onClick={() => setMode(mode === 'dark' ? 'light' : 'dark')}
                sx={{ 
                  color: 'rgba(255,255,255,0.8)',
                  '&:hover': { 
                    color: '#fff',
                    backgroundColor: 'rgba(255,255,255,0.1)' 
                  }
                }}
              >
                {mode === 'dark' ? <LightModeIcon fontSize="small" /> : <DarkModeIcon fontSize="small" />}
              </IconButton>
            </Stack>
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      <motion.div
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        <Grid container spacing={1.5}>
          {subscriptions.map((subscription) => (
            <Grid item xs={12} sm={6} md={3} key={subscription.id}>
              <motion.div variants={cardVariants}>
                <Card sx={cardStyle}>
                  <CardContent sx={{ p: '10px !important', height: '100%' }}>
                    <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1.5 }}>
                      <Typography variant="h6">{subscription.name}</Typography>
                      <Stack direction="row" spacing={0.5}>
                        <IconButton 
                          size="small" 
                          onClick={() => handleOpenDialog(subscription)}
                          sx={{
                            color: 'text.secondary',
                            '&:hover': {
                              color: 'primary.main',
                              backgroundColor: 'action.hover',
                            },
                          }}
                        >
                          <EditIcon fontSize="small" />
                        </IconButton>
                        <IconButton 
                          size="small" 
                          onClick={() => handleDelete(subscription.id)}
                          sx={{
                            color: 'text.secondary',
                            '&:hover': {
                              color: 'error.main',
                              backgroundColor: 'action.hover',
                            },
                          }}
                        >
                          <DeleteIcon fontSize="small" />
                        </IconButton>
                      </Stack>
                    </Box>
                    <Stack spacing={1}>
                      <Typography variant="body2" color="text.secondary">
                        更新时间: {subscription.updateTime}
                      </Typography>
                      <Typography variant="body2" color="text.secondary">
                        到期时间: {subscription.expireTime}
                      </Typography>
                      <Box>
                        <Typography variant="body2" color="text.secondary" gutterBottom sx={{ mb: 0.5 }}>
                          流量使用: {formatBytes(subscription.usedTraffic)} / {formatBytes(subscription.totalTraffic)}
                        </Typography>
                        <LinearProgress 
                          variant="determinate" 
                          value={(subscription.usedTraffic / subscription.totalTraffic) * 100}
                          sx={{ 
                            height: 4, 
                            borderRadius: 2,
                            bgcolor: (theme) => 
                              theme.palette.mode === 'dark' 
                                ? 'rgba(255, 255, 255, 0.12)' 
                                : 'rgba(0, 0, 0, 0.08)',
                            '.MuiLinearProgress-bar': {
                              borderRadius: 2,
                            }
                          }}
                        />
                      </Box>
                    </Stack>
                  </CardContent>
                </Card>
              </motion.div>
            </Grid>
          ))}
        </Grid>
      </motion.div>

      <Box sx={{ position: 'fixed', right: 24, bottom: 24 }}>
        <Stack direction="row" spacing={2}>
          <Button
            variant="contained"
            size="large"
            startIcon={<SyncIcon />}
            onClick={fetchSubscriptions}
            disabled={loading}
            sx={{
              borderRadius: 2,
              px: 3,
              boxShadow: (theme) =>
                theme.palette.mode === 'dark'
                  ? '0 4px 12px 0 rgba(0,0,0,0.4)'
                  : '0 4px 12px 0 rgba(31,38,135,0.2)',
              '&:hover': {
                boxShadow: (theme) =>
                  theme.palette.mode === 'dark'
                    ? '0 6px 16px 0 rgba(0,0,0,0.5)'
                    : '0 6px 16px 0 rgba(31,38,135,0.3)',
              },
            }}
          >
            刷新订阅
          </Button>
          <Button
            variant="contained"
            size="large"
            startIcon={<AddIcon />}
            onClick={() => handleOpenDialog()}
            sx={{
              borderRadius: 2,
              px: 3,
              boxShadow: (theme) =>
                theme.palette.mode === 'dark'
                  ? '0 4px 12px 0 rgba(0,0,0,0.4)'
                  : '0 4px 12px 0 rgba(31,38,135,0.2)',
              '&:hover': {
                boxShadow: (theme) =>
                  theme.palette.mode === 'dark'
                    ? '0 6px 16px 0 rgba(0,0,0,0.5)'
                    : '0 6px 16px 0 rgba(31,38,135,0.3)',
              },
            }}
          >
            添加订阅
          </Button>
        </Stack>
      </Box>

      <Dialog 
        open={openDialog} 
        onClose={handleCloseDialog} 
        maxWidth="sm" 
        fullWidth
        PaperProps={{
          sx: {
            borderRadius: 2,
            boxShadow: theme.palette.mode === 'dark'
              ? '0 8px 24px 0 rgba(0,0,0,0.4)'
              : '0 8px 24px 0 rgba(31,38,135,0.2)',
          }
        }}
      >
        <DialogTitle>
          {selectedSubscription ? '编辑订阅' : '添加订阅'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="订阅名称"
                  value={editSubscription.name}
                  onChange={(e) => setEditSubscription({ ...editSubscription, name: e.target.value })}
                  size="small"
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      '&:hover fieldset': {
                        borderColor: 'primary.main',
                      },
                    },
                  }}
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="订阅地址"
                  value={editSubscription.url}
                  onChange={(e) => setEditSubscription({ ...editSubscription, url: e.target.value })}
                  size="small"
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      '&:hover fieldset': {
                        borderColor: 'primary.main',
                      },
                    },
                  }}
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="更新间隔（秒）"
                  type="number"
                  value={editSubscription.interval}
                  onChange={(e) => setEditSubscription({ ...editSubscription, interval: parseInt(e.target.value) })}
                  size="small"
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      '&:hover fieldset': {
                        borderColor: 'primary.main',
                      },
                    },
                  }}
                />
              </Grid>
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button 
            onClick={handleCloseDialog} 
            size="small"
            sx={{
              color: 'text.secondary',
              '&:hover': {
                backgroundColor: 'action.hover',
              },
            }}
          >
            取消
          </Button>
          <Button 
            variant="contained" 
            onClick={handleSave}
            disabled={loading}
            size="small"
            sx={{
              px: 3,
              boxShadow: 'none',
              '&:hover': {
                boxShadow: 'none',
              },
            }}
          >
            保存
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default Subscriptions;
